		f.checkForUpdates(cmd)

		// Call the original PersistentPreRun if it exists
		if rootCmd.PersistentPreRun != nil {
			rootCmd.PersistentPreRun(cmd, args)
		}
		return nil
	}

	// Display update notification and staleness hints after command completes
	rootCmd.PersistentPostRunE = func(cmd *cobra.Command, args []string) error {
		if err := f.displayUpdateNotification(cmd); err != nil {
			return err
		}
		f.displayStalenessHints(cmd)
		return nil
	}

	// Add all subcommands
	f.registerSubcommands(rootCmd)

	// Keep the persona APIs in the static production graph. Cobra dispatch
	// does not always show up in deadcode RTA, so this explicit hook keeps the
	// real CLI implementations visible without changing runtime behavior.
	persona.KeepReachabilityForDeadcode()
	metaprompt.KeepReachabilityForDeadcode()

	return rootCmd
}

func formattedVersion(version string) string {
	if version == "dev" {
		return "v0.0.1-dev"
	}
	if !strings.HasPrefix(version, "v") {
		return "v" + version
	}
	return version
}

func (f *CommandFactory) versionOutput() string {
	return fmt.Sprintf("DDx %s\nCommit: %s\nBuilt: %s\n", formattedVersion(f.Version), f.Commit, f.Date)
}

// initConfig initializes configuration for this command instance
func (f *CommandFactory) initConfig(cfgFile, libPath string) {
	// Store library path override if provided
	if libPath != "" {
		_ = os.Setenv("DDX_LIBRARY_BASE_PATH", libPath)
	}

	if cfgFile != "" {
		// Use config file from the flag
		f.viperInstance.SetConfigFile(cfgFile)
	} else {
		// Find home directory
		home, err := os.UserHomeDir()
		if err == nil {
			// Search for config in home directory with name ".ddx" (without extension)
			f.viperInstance.AddConfigPath(home)
			f.viperInstance.AddConfigPath(".")
			f.viperInstance.SetConfigType("yaml")
			f.viperInstance.SetConfigName(".ddx")
		}
	}

	f.viperInstance.AutomaticEnv() // read in environment variables that match

	// If a config file is found, read it in
	if err := f.viperInstance.ReadInConfig(); err == nil {
		if verbose := f.viperInstance.GetBool("verbose"); verbose {
			_, _ = fmt.Fprintln(os.Stderr, "Using config file:", f.viperInstance.ConfigFileUsed())
		}
	}
}

// checkForUpdates performs automatic update check (synchronous, once per 24h)
func (f *CommandFactory) checkForUpdates(cmd *cobra.Command) {
	// Check if disabled via env var
	if os.Getenv("DDX_DISABLE_UPDATE_CHECK") == "1" {
		return
	}

	// Load config
	cfg, err := config.Load()
	if err != nil {
		// Silent failure - use defaults
		cfg = config.DefaultNewConfig()
	}

	// Check if disabled via config
	if cfg.UpdateCheck != nil && !cfg.UpdateCheck.Enabled {
		return
	}

	// Create checker and perform check (synchronous)
	checker := update.NewChecker(f.Version, cfg)
	f.updateMu.Lock()
	f.updateChecker = checker
	f.updateDone = make(chan struct{})
	done := f.updateDone
	f.updateMu.Unlock()

	// Run the check asynchronously so command startup is never blocked.
	go func() {
		defer close(done)
		_, _ = checker.CheckForUpdate(context.Background())
		// Also refresh plugin version cache while we have a network call in flight.

	if persona == nil {
		return fmt.Errorf("persona not found")
	}

	// Emit the deprecation notice to stderr before the persona body so the
	// warning is visible even when the caller pipes stdout elsewhere.
	if notice := deprecationNoticeFor(persona.Name); notice != "" {
		_, _ = fmt.Fprintln(os.Stderr, notice)
	}

	// Parse metadata from content
	metadata := parsePersonaMetadata(persona.Content)
	if metadata != nil {
		// Display formatted metadata
		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Name: %s\n", metadata.Name)
		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Roles: %s\n", strings.Join(metadata.Roles, ", "))
		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Description: %s\n", metadata.Description)
		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Tags: %s\n", strings.Join(metadata.Tags, ", "))

		// Display content after frontmatter
		lines := strings.Split(persona.Content, "\n")
		contentStart := 0
		foundEnd := false
		for i, line := range lines {
			if i > 0 && line == "---" {
				contentStart = i + 1
				foundEnd = true
				break
			}
		}
		if foundEnd && contentStart < len(lines) {
			_, _ = fmt.Fprintln(cmd.OutOrStdout())
			_, _ = fmt.Fprint(cmd.OutOrStdout(), strings.Join(lines[contentStart:], "\n"))
		}
	} else {
		// No frontmatter, display raw content
		_, _ = fmt.Fprint(cmd.OutOrStdout(), persona.Content)
	}
	return nil
}

// displayBindings displays persona bindings to the user
func displayBindings(cmd *cobra.Command, bindings PersonaBindings) error {
	if len(bindings) == 0 {
		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "No persona bindings configured")
		return nil
	}

	_, _ = fmt.Fprintln(cmd.OutOrStdout(), "Current Persona Bindings:")
	_, _ = fmt.Fprintln(cmd.OutOrStdout())

	// Create tabwriter for aligned output
	w := tabwriter.NewWriter(cmd.OutOrStdout(), 0, 0, 2, ' ', 0)
	_, _ = fmt.Fprintln(w, "ROLE\tPERSONA")
	_, _ = fmt.Fprintln(w, "----\t-------")

	for role, persona := range bindings {
		_, _ = fmt.Fprintf(w, "%s\t%s\n", role, persona)
	}

	_ = w.Flush()
	return nil
}

// displayPersonaStatus displays persona status to the user
func displayPersonaStatus(cmd *cobra.Command, status PersonaStatus) error {
	if !status.HasCLAUDEFile {
		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "No CLAUDE.md file found - no personas loaded")
		return nil
	}

	if len(status.LoadedPersonas) > 0 {
		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "Loaded Personas:")
		for i, persona := range status.LoadedPersonas {
			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "  - %s (%s)\n", persona, status.LoadedRoles[i])
		}
	} else {
		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "No personas currently loaded")
	}

	if status.BindingsCount > 0 {
		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "\n%d persona binding(s) configured\n", status.BindingsCount)
	}

	return nil
}

// displayLoadResult displays the result of loading personas
func displayLoadResult(cmd *cobra.Command, requestedPersonas []string, loadedPersonas []string) error {
	if len(requestedPersonas) > 0 {
		// Specific personas loaded
		if len(loadedPersonas) == 1 {
			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Loaded persona '%s' into CLAUDE.md\n", loadedPersonas[0])
		} else {
			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Loaded %d personas into CLAUDE.md\n", len(loadedPersonas))
		}
	} else {
		// All bound personas loaded
		if len(loadedPersonas) > 0 {
			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Loaded %d personas (%s) into CLAUDE.md\n",
				len(loadedPersonas), strings.Join(loadedPersonas, ", "))
		} else {
			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "No bound personas to load")
		}
	}
	return nil
}

