168	// buildPersonasSection creates the personas section content
169	func (c *ClaudeInjectorImpl) buildPersonasSection(personas map[string]*Persona) string {
170		var sections []string
171	
172		sections = append(sections, PersonasStartMarker)
173		sections = append(sections, PersonasHeader)
174		sections = append(sections, "")
175	
176		// Sort roles for consistent output (optional, but helpful for testing)
177		roles := make([]string, 0, len(personas))
178		for role := range personas {
179			roles = append(roles, role)
180		}
181		sort.Strings(roles)
182	
183		for _, role := range roles {
184			persona := personas[role]
185			roleDisplay := formatRoleDisplay(role)
186			personaHeader := fmt.Sprintf("### %s: %s", roleDisplay, persona.Name)
187			sections = append(sections, personaHeader)
188			sections = append(sections, persona.Content)
189			sections = append(sections, "")
190		}
191	
192		sections = append(sections, PersonasFooter)
193		sections = append(sections, PersonasEndMarker)
194	
195		return strings.Join(sections, "\n")
196	}
