260	// saveClaudeFile saves content to the CLAUDE.md file
261	func (c *ClaudeInjectorImpl) saveClaudeFile(content string) error {
262		// Clean up trailing whitespace but preserve structure
263		lines := strings.Split(content, "\n")
264		for i, line := range lines {
265			lines[i] = strings.TrimRight(line, " \t")
266		}
267	
268		// Remove trailing empty lines
269		for len(lines) > 0 && lines[len(lines)-1] == "" {
270			lines = lines[:len(lines)-1]
271		}
272	
273		cleanContent := strings.Join(lines, "\n")
274	
275		if err := os.WriteFile(c.claudeFilePath, []byte(cleanContent), 0644); err != nil {
276			return NewPersonaError(ErrorFileOperation,
277				fmt.Sprintf("failed to write CLAUDE.md file %s", c.claudeFilePath), err)
278		}
279	
280		return nil
281	}
