 15	// PersonaLoaderImpl implements the PersonaLoader interface.
 16	//
 17	// A loader can own up to two source directories:
 18	//   - libraryDir: read-only, shared across projects.
 19	//   - projectDir: project-local (`.ddx/personas`). When a project persona has
 20	//     the same name as a library persona, the project persona wins for that
 21	//     project's bindings.
 22	type PersonaLoaderImpl struct {
 23		// libraryDir is the legacy single directory and remains in use when the
 24		// loader is constructed via NewPersonaLoaderWithDir for test fixtures.
 25		personasDir string
 26		projectDir  string
 27	}
 28	
 29	// NewPersonaLoader creates a new persona loader rooted at the project's
 30	// working directory. It discovers the library path from config and the
 31	// project-local `.ddx/personas` directory.
 32	func NewPersonaLoader(workingDir string) PersonaLoader {
 33		libraryDir := resolveLibraryPersonasDir(workingDir)
 34		projectDir := resolveProjectPersonasDir(workingDir)
 35		return NewPersonaLoaderWithDirs(libraryDir, projectDir)
 36	}
 37	
 38	// NewPersonaLoaderWithDir creates a new persona loader with a specific
 39	// library directory. Kept for tests and back-compat callers that only need
 40	// the library source.
 41	func NewPersonaLoaderWithDir(dir string) PersonaLoader {
 42		return &PersonaLoaderImpl{
 43			personasDir: dir,
 44		}
 45	}
 46	
 47	// NewPersonaLoaderWithDirs creates a loader with explicit library and project
 48	// directories. Either may be empty to disable that source.
 49	func NewPersonaLoaderWithDirs(libraryDir, projectDir string) PersonaLoader {
 50		loader := NewPersonaLoaderWithDir(libraryDir).(*PersonaLoaderImpl)
 51		loader.projectDir = projectDir
 52		return loader
 53	}
 54	
 55	// resolveLibraryPersonasDir resolves the library persona directory.
 56	func resolveLibraryPersonasDir(workingDir string) string {
 57		cfg, err := config.LoadWithWorkingDir(workingDir)
 58		if err != nil {
 59			_, _ = fmt.Fprintf(os.Stderr, "DDx config not found; run \"ddx init\" to bootstrap project\n")
 60			return ""
 61		}
 62		if cfg.Library == nil || cfg.Library.Path == "" {
 63			return ""
 64		}
 65		libPath := cfg.Library.Path
 66		if !filepath.IsAbs(libPath) && workingDir != "" {
 67			libPath = filepath.Join(workingDir, libPath)
 68		}
 69		return filepath.Join(libPath, "personas")
 70	}
 71	
 72	// resolveProjectPersonasDir returns the project-local persona directory.
 73	func resolveProjectPersonasDir(workingDir string) string {
 74		if workingDir == "" {
 75			return ""
 76		}
 77		return filepath.Join(workingDir, ".ddx", "personas")
 78	}
 79	
 80	// LoadPersona loads a persona by name. Project-local personas override
 81	// library personas with the same name.
 82	func (l *PersonaLoaderImpl) LoadPersona(name string) (*Persona, error) {
 83		if name == "" {
 84			return nil, NewPersonaError(ErrorValidation, "persona name cannot be empty", nil)
 85		}
 86	
 87		if l.projectDir != "" {
 88			candidate := filepath.Join(l.projectDir, name+PersonaFileExtension)
 89			if fileExists(candidate) {
 90				return readPersonaFile(candidate, SourceProject)
 91			}
 92		}
 93	
 94		if l.personasDir != "" {
 95			candidate := filepath.Join(l.personasDir, name+PersonaFileExtension)
 96			if fileExists(candidate) {
 97				return readPersonaFile(candidate, SourceLibrary)
 98			}
 99		}
100	
101		return nil, NewPersonaError(ErrorPersonaNotFound,
102			fmt.Sprintf("persona '%s' not found", name), nil)
103	}
104	
105	// readPersonaFile reads a single persona file and tags it with its source.
106	func readPersonaFile(filePath, source string) (*Persona, error) {
107		content, err := os.ReadFile(filePath)
108		if err != nil {
109			return nil, NewPersonaError(ErrorFileOperation,
110				fmt.Sprintf("failed to read persona file %s", filePath), err)
111		}
112		if len(content) > MaxPersonaFileSize {
113			return nil, NewPersonaError(ErrorValidation,
114				fmt.Sprintf("persona file %s exceeds maximum size of %d bytes", filePath, MaxPersonaFileSize), nil)
115		}
116		persona, err := parsePersona(content)
117		if err != nil {
118			return nil, NewPersonaError(ErrorInvalidPersona,
119				fmt.Sprintf("failed to parse persona %s", filePath), err)
120		}
121		persona.Source = source
122		persona.FilePath = filePath
123		return persona, nil
124	}
