180	// FindByRole returns personas that can fulfill the specified role.
181	func (l *PersonaLoaderImpl) FindByRole(role string) ([]*Persona, error) {
182		if role == "" {
183			return nil, NewPersonaError(ErrorValidation, "role cannot be empty", nil)
184		}
185	
186		allPersonas, err := l.ListPersonas()
187		if err != nil {
188			return nil, err
189		}
190	
191		var matchingPersonas []*Persona
192	
193		for _, persona := range allPersonas {
194			for _, personaRole := range persona.Roles {
195				if personaRole == role {
196					matchingPersonas = append(matchingPersonas, persona)
197					break
198				}
199			}
200		}
201	
202		return matchingPersonas, nil
203	}
