205	// FindByTags returns personas that have all the specified tags.
206	func (l *PersonaLoaderImpl) FindByTags(tags []string) ([]*Persona, error) {
207		if len(tags) == 0 {
208			return nil, NewPersonaError(ErrorValidation, "at least one tag must be specified", nil)
209		}
210	
211		allPersonas, err := l.ListPersonas()
212		if err != nil {
213			return nil, err
214		}
215	
216		var matchingPersonas []*Persona
217	
218		for _, persona := range allPersonas {
219			if hasAllTags(persona.Tags, tags) {
220				matchingPersonas = append(matchingPersonas, persona)

